export default {
  name: 'new',
  data () {
    return {
      saleShow: false,
      topShow: false,
      bottomShow: false,
      onePieceShow: false,
      homeWearShow: false,
      accessoryShow: false,
      items: [
        {
          id:1,
          name: "無領打褶澎袖上衣",
          price: {
            NTD: 590
          },
          src: "./assets/img/new-in/top/top-1.jpg"
        },
        {
          id:2,
          name: "小領片男友襯衫",
          price: {
            NTD: 690
          },
          src: "./assets/img/new-in/top/top-2.jpg"
        },
        {
          id:3,
          name: "質感小設計打摺西裝褲衣",
          price: {
            NTD: 690
          },
          src: "./assets/img/new-in/top/top-1.jpg"
        },
        {
          id:4,
          name: "時髦可頌麵包戒指",
          price: {
            NTD: 490
          },
          src: "./assets/img/new-in/accessory/ring.jpg"
        }
      ]
    }
  },
  async mounted () {
    const res = await fetch('.../items.json')
    const data = await res.json()
    this.items = data
  }
}
